package bead

import (
	"fmt"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

type backendConformanceCase struct {
	name    string
	backend string
}

func backendConformanceCases() []backendConformanceCase {
	return []backendConformanceCase{
		{name: "jsonl", backend: BackendJSONL},
		{name: "axon", backend: BackendAxon},
	}
}

func forEachBackendConformanceCase(t *testing.T, fn func(*testing.T, backendConformanceCase)) {
	t.Helper()
	for _, tc := range backendConformanceCases() {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()
			fn(t, tc)
		})
	}
}

func runBackendConformanceSuite(t *testing.T, tc backendConformanceCase) {
	t.Helper()
	makeStore := func(t *testing.T) *Store {
		t.Helper()
		switch tc.backend {
		case BackendJSONL:
			return newJSONLStore(t)
		case BackendAxon:
			return newAxonStore(t)
		default:
			t.Fatalf("unsupported backend %q", tc.backend)
			return nil
		}
	}

	t.Run("create-get", func(t *testing.T) {
		t.Parallel()
		s := makeStore(t)

		b := &Bead{Title: "first", Description: "round-trip"}
		require.NoError(t, s.Create(b))
		require.NotEmpty(t, b.ID)

		got, err := s.Get(b.ID)
		require.NoError(t, err)
		assert.Equal(t, "first", got.Title)
		assert.Equal(t, "round-trip", got.Description)
		assert.Equal(t, StatusOpen, got.Status)
	})

	t.Run("update", func(t *testing.T) {
		t.Parallel()
		s := makeStore(t)

		b := &Bead{Title: "to-update"}
		require.NoError(t, s.Create(b))

		require.NoError(t, s.Update(b.ID, func(bb *Bead) {
			bb.Notes = "added by update"
			bb.Priority = 3
		}))

		got, err := s.Get(b.ID)
		require.NoError(t, err)
		assert.Equal(t, "added by update", got.Notes)
		assert.Equal(t, 3, got.Priority)
	})

	t.Run("claim", func(t *testing.T) {
		t.Parallel()
		s := makeStore(t)

		b := &Bead{Title: "claimable"}
		require.NoError(t, s.Create(b))

		require.NoError(t, s.Claim(b.ID, "alice"))
		got, err := s.Get(b.ID)
		require.NoError(t, err)
		assert.Equal(t, StatusInProgress, got.Status)
		assert.Equal(t, "alice", got.Owner)
		require.NotNil(t, got.Extra)
		assert.NotEmpty(t, got.Extra["claimed-at"])

		err = s.Claim(b.ID, "bob")
		require.Error(t, err)

		require.NoError(t, s.Unclaim(b.ID))
		got, err = s.Get(b.ID)
		require.NoError(t, err)
		assert.Equal(t, StatusOpen, got.Status)
		assert.Empty(t, got.Owner)
	})

	t.Run("deps", func(t *testing.T) {
		t.Parallel()
		s := makeStore(t)

		root := &Bead{Title: "root"}
		child := &Bead{Title: "child"}
		require.NoError(t, s.Create(root))
		require.NoError(t, s.Create(child))

		require.NoError(t, s.DepAdd(child.ID, root.ID))
		got, err := s.Get(child.ID)
		require.NoError(t, err)
		require.Len(t, got.Dependencies, 1)
		assert.Equal(t, root.ID, got.Dependencies[0].DependsOnID)

		tree, err := s.DepTree(root.ID)
		require.NoError(t, err)
		assert.Contains(t, tree, root.ID)

		require.NoError(t, s.DepRemove(child.ID, root.ID))
		got, err = s.Get(child.ID)
		require.NoError(t, err)
		assert.Empty(t, got.Dependencies)
	})

	t.Run("events-close", func(t *testing.T) {
		t.Parallel()
		s := makeStore(t)

		b := &Bead{Title: "with-events"}
		require.NoError(t, s.Create(b))

		for i := 0; i < 3; i++ {
			require.NoError(t, s.AppendEvent(b.ID, BeadEvent{
				Kind:    "test",
				Summary: fmt.Sprintf("event-%d", i),
				Body:    fmt.Sprintf("body-%d", i),
				Actor:   "tester",
			}))
		}

		events, err := s.Events(b.ID)
		require.NoError(t, err)
		require.Len(t, events, 3)
		for i, e := range events {
			assert.Equal(t, fmt.Sprintf("event-%d", i), e.Summary)
		}

		require.NoError(t, s.Close(b.ID))
		got, err := s.Get(b.ID)
		require.NoError(t, err)
		assert.Equal(t, StatusClosed, got.Status)
		events, err = s.Events(b.ID)
		require.NoError(t, err)
		assert.Len(t, events, 3)
	})
}

func TestBackendConformance(t *testing.T) {
	forEachBackendConformanceCase(t, func(t *testing.T, tc backendConformanceCase) {
		runBackendConformanceSuite(t, tc)
	})
}

package bead

import (
	"fmt"
	"math/rand"
	"strings"
	"sync"
	"testing"
	"unicode"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// newTestBackend returns a Backend rooted at a fresh temp dir for the explicit
// backend name supplied by the caller. The chaos suite uses it so both JSONL
// and axon run through the same Backend interface surface rather than one path
// silently defaulting to JSONL.
func newTestBackend(t *testing.T, backend string) Backend {
	t.Helper()
	switch backend {
	case BackendJSONL:
		return newJSONLStore(t)
	case BackendAxon:
		return newAxonStore(t)
	default:
		t.Fatalf("unsupported chaos backend %q", backend)
		return nil
	}
}

// chaosBackend names a backend constructor for the parameterized chaos suite.
// Per ddx-743bc194, every backend-agnostic chaos scenario must run against both
// the JSONL default and the axon backend so a regression in either path fails
// the same suite.
type chaosBackend struct {
	name    string
	backend string
}

func chaosBackends() []chaosBackend {
	return []chaosBackend{
		{name: "jsonl", backend: BackendJSONL},
		{name: "axon", backend: BackendAxon},
	}
}

// forEachChaosBackend runs fn once per backend as a parallel subtest. The
// subtest receives a fresh Backend, so scenarios stay isolated per backend.
func forEachChaosBackend(t *testing.T, fn func(*testing.T, Backend)) {
	t.Helper()
	for _, bf := range chaosBackends() {
		bf := bf
		t.Run(bf.name, func(t *testing.T) {
			t.Parallel()
			fn(t, newTestBackend(t, bf.backend))
		})
	}
}

// TestChaos_ConcurrentAppendSafety spawns 10 goroutines each creating 10 beads
// against the same store. Verifies all 100 beads exist, no duplicates, no corruption.
func TestChaos_ConcurrentAppendSafety(t *testing.T) {
	forEachChaosBackend(t, func(t *testing.T, s Backend) {
		const goroutines = 10
		const beadsEach = 10
		const total = goroutines * beadsEach

		var wg sync.WaitGroup
		errCh := make(chan error, total)

		for g := 0; g < goroutines; g++ {
			g := g
			wg.Add(1)
			go func() {
				defer wg.Done()
				for i := 0; i < beadsEach; i++ {
					b := &Bead{Title: fmt.Sprintf("goroutine-%d-bead-%d", g, i)}
					if err := s.Create(b); err != nil {
						errCh <- fmt.Errorf("goroutine %d create %d: %w", g, i, err)
					}
				}
			}()
		}

		wg.Wait()
		close(errCh)

		var errs []error
		for err := range errCh {
			errs = append(errs, err)
		}
		require.Empty(t, errs, "concurrent creates must not error: %v", errs)

		beads, err := s.ReadAll()
		require.NoError(t, err)
		assert.Len(t, beads, total, "all %d beads must be present", total)

		// Check for duplicates
		seen := make(map[string]int)
		for _, b := range beads {
			seen[b.ID]++
		}
		for id, count := range seen {
			assert.Equal(t, 1, count, "bead %s appears %d times (duplicate)", id, count)
		}

		// Check no corruption: every bead must have a valid ID, title, and status
		for _, b := range beads {
			assert.NotEmpty(t, b.ID, "bead ID must not be empty")
			assert.NotEmpty(t, b.Title, "bead title must not be empty")
			assert.Contains(t, []string{StatusOpen, StatusInProgress, StatusClosed}, b.Status,
				"bead %s has invalid status %q", b.ID, b.Status)
		}
	})
}

// TestChaos_AtomicStatusTransitions spawns 5 goroutines each cycling a single
// bead through open→in_progress→closed→open. After all iterations the bead
// must have a valid status and the store must be fully parseable.
func TestChaos_AtomicStatusTransitions(t *testing.T) {
	forEachChaosBackend(t, func(t *testing.T, s Backend) {
		b := &Bead{Title: "status-churn"}
		require.NoError(t, s.Create(b))
		id := b.ID

		const goroutines = 5
		const iterations = 20

		statuses := []string{StatusOpen, StatusInProgress, StatusClosed}
		var wg sync.WaitGroup

		for g := 0; g < goroutines; g++ {
			g := g
			wg.Add(1)
			go func() {
				defer wg.Done()
				for i := 0; i < iterations; i++ {
					next := statuses[(g+i)%len(statuses)]
					// Ignore errors: contention may cause transient failures that are
					// acceptable (e.g. attempting to set a status that is already set).
					// The critical invariant is no corruption.
					_ = s.Update(id, func(bead *Bead) {
						bead.Status = next
					})
				}
			}()
		}

		wg.Wait()

		// Bead must still exist with a valid status
		got, err := s.Get(id)
		require.NoError(t, err, "bead must be readable after concurrent status updates")
		assert.Contains(t, []string{StatusOpen, StatusInProgress, StatusClosed}, got.Status,
			"bead must have a valid status after concurrent updates")

		// Store must be parseable end-to-end
		allBeads, err := s.ReadAll()
		require.NoError(t, err, "store must be parseable after concurrent status transitions")
		assert.NotEmpty(t, allBeads, "store must not be empty after updates")

		// Verify no partial writes: every entry must decode cleanly
		for _, bead := range allBeads {
			assert.NotEmpty(t, bead.ID)
			assert.NotEmpty(t, bead.Title)
		}
	})
}

